<script setup lang="ts">
import { onMounted, reactive, ref } from 'vue'
import { Edit, Plus, Search } from '@element-plus/icons-vue'
import { ElMessage } from 'element-plus'
import { adminApi, catalogApi, type Brand, type Category, type ProductDetail, type ProductListItem, type Sku } from '@/api/services'

const keyword = ref(''); const status = ref<number>(); const products = ref<ProductListItem[]>([]); const total = ref(0); const page = ref(1); const loading = ref(false)
const productDialog = ref(false); const productSaving = ref(false); const editingId = ref<number>(); const activeProduct = ref<ProductDetail>(); const categories = ref<Category[]>([]); const brands = ref<Brand[]>([])
const productForm = reactive({ title: '', subtitle: '', description: '', mainImageUrl: '', categoryId: undefined as number | undefined, brandId: undefined as number | undefined, status: 1 })
const skuDialog = ref(false); const skuSaving = ref(false); const editingSkuId = ref<number>(); const skuForm = reactive({ skuCode: '', specJson: '{}', price: 0.01, availableStock: 0, status: 1 })
const load = async () => { loading.value = true; try { const result = await adminApi.products({ keyword: keyword.value || undefined, status: status.value, page: page.value, size: 20 }); products.value = result.items; total.value = result.total } finally { loading.value = false } }
const loadOptions = async () => { if (!categories.value.length || !brands.value.length) [categories.value, brands.value] = await Promise.all([catalogApi.categories(), catalogApi.brands()]) }
const openCreate = async () => { await loadOptions(); editingId.value = undefined; activeProduct.value = undefined; Object.assign(productForm, { title: '', subtitle: '', description: '', mainImageUrl: '', categoryId: undefined, brandId: undefined, status: 1 }); productDialog.value = true }
const openEdit = async (id: number) => { await loadOptions(); const product = await adminApi.product(id); editingId.value = id; activeProduct.value = product; Object.assign(productForm, { title: product.title, subtitle: product.subtitle || '', description: product.description || '', mainImageUrl: product.mainImageUrl || '', categoryId: product.categoryId, brandId: product.brandId, status: product.status ?? 1 }); productDialog.value = true }
const saveProduct = async () => { if (!productForm.title.trim() || !productForm.mainImageUrl.trim() || !productForm.categoryId || !productForm.brandId) return ElMessage.warning('请完整填写商品名称、图片 URL、分类和品牌'); productSaving.value = true; try { activeProduct.value = editingId.value ? await adminApi.updateProduct(editingId.value, productForm) : await adminApi.createProduct(productForm); editingId.value = activeProduct.value.id; ElMessage.success('商品信息已保存'); await load() } finally { productSaving.value = false } }
const openSku = (sku?: Sku) => { editingSkuId.value = sku?.id; Object.assign(skuForm, { skuCode: sku?.skuCode || '', specJson: sku?.specJson || '{}', price: Number(sku?.price || 0.01), availableStock: sku?.availableStock || 0, status: sku?.status ?? 1 }); skuDialog.value = true }
const saveSku = async () => { if (!editingId.value) return; try { JSON.parse(skuForm.specJson) } catch { return ElMessage.warning('规格必须是合法 JSON') } if (!skuForm.skuCode.trim()) return ElMessage.warning('请填写 SKU 编码'); skuSaving.value = true; try { if (editingSkuId.value) await adminApi.updateSku(editingId.value, editingSkuId.value, skuForm); else await adminApi.createSku(editingId.value, skuForm); activeProduct.value = await adminApi.product(editingId.value); skuDialog.value = false; ElMessage.success('SKU 已保存'); await load() } finally { skuSaving.value = false } }
onMounted(load)
</script>

<template><div><div class="admin-page-title"><div><span>商品中心</span><h1>商品管理</h1><p>维护商品、图片 URL、规格、价格与库存。</p></div><el-button type="primary" :icon="Plus" @click="openCreate">新增商品</el-button></div><section class="admin-card"><div class="toolbar"><el-input v-model="keyword" placeholder="搜索商品名称" :prefix-icon="Search" clearable @keyup.enter="page = 1; load()" /><el-select v-model="status" placeholder="全部状态" clearable><el-option label="上架" :value="1" /><el-option label="下架" :value="0" /></el-select><el-button @click="page = 1; load()">筛选</el-button></div><el-table v-loading="loading" :data="products"><el-table-column label="商品信息" min-width="310"><template #default="scope"><div class="table-product"><img :src="scope.row.mainImageUrl || 'https://placehold.co/100x100/eaf3ff/1677ff?text=DingDong'" :alt="scope.row.title" /><div><b>{{ scope.row.title }}</b><small>{{ scope.row.subtitle }}</small></div></div></template></el-table-column><el-table-column label="售价" width="120"><template #default="scope">¥{{ Number(scope.row.minPrice ?? scope.row.price ?? 0).toFixed(2) }}</template></el-table-column><el-table-column prop="sales" label="销量" width="90" /><el-table-column label="状态" width="90"><template #default="scope"><el-tag :type="scope.row.status === 1 ? 'success' : 'info'">{{ scope.row.status === 1 ? '上架' : '下架' }}</el-tag></template></el-table-column><el-table-column label="操作" width="110"><template #default="scope"><el-button link type="primary" :icon="Edit" @click="openEdit(scope.row.id)">编辑</el-button></template></el-table-column></el-table><div class="admin-pagination"><el-pagination v-model:current-page="page" background layout="total, prev, pager, next" :page-size="20" :total="total" @current-change="load" /></div></section><el-dialog v-model="productDialog" :title="editingId ? '编辑商品' : '新增商品'" width="760px"><el-form :model="productForm" label-width="95px"><el-form-item label="商品名称" required><el-input v-model="productForm.title" /></el-form-item><el-form-item label="商品副标题"><el-input v-model="productForm.subtitle" /></el-form-item><el-form-item label="商品描述"><el-input v-model="productForm.description" type="textarea" :rows="3" /></el-form-item><el-form-item label="图片 URL" required><div class="url-image-field"><el-input v-model="productForm.mainImageUrl" placeholder="https://example.com/product.png" /><img v-if="productForm.mainImageUrl" :src="productForm.mainImageUrl" alt="商品图片预览" /></div></el-form-item><el-form-item label="分类" required><el-select v-model="productForm.categoryId" style="width: 100%"><el-option v-for="item in categories" :key="item.id" :label="item.name" :value="item.id" /></el-select></el-form-item><el-form-item label="品牌" required><el-select v-model="productForm.brandId" style="width: 100%"><el-option v-for="item in brands" :key="item.id" :label="item.name" :value="item.id" /></el-select></el-form-item><el-form-item label="商品状态"><el-radio-group v-model="productForm.status"><el-radio-button :value="1">上架</el-radio-button><el-radio-button :value="0">下架</el-radio-button></el-radio-group></el-form-item></el-form><template v-if="editingId"><div class="sku-heading"><div><h3>SKU 规格</h3><p>维护规格 JSON、价格、库存和上下架状态</p></div><el-button type="primary" plain :icon="Plus" @click="openSku()">新增 SKU</el-button></div><el-table :data="activeProduct?.skus || []" size="small"><el-table-column prop="skuCode" label="SKU 编码" min-width="150" /><el-table-column prop="specJson" label="规格 JSON" min-width="180" show-overflow-tooltip /><el-table-column label="价格" width="90"><template #default="scope">¥{{ Number(scope.row.price).toFixed(2) }}</template></el-table-column><el-table-column prop="availableStock" label="库存" width="75" /><el-table-column label="状态" width="75"><template #default="scope">{{ scope.row.status === 1 ? '上架' : '下架' }}</template></el-table-column><el-table-column label="操作" width="80"><template #default="scope"><el-button link type="primary" @click="openSku(scope.row)">编辑</el-button></template></el-table-column></el-table></template><template #footer><el-button @click="productDialog = false">关闭</el-button><el-button type="primary" :loading="productSaving" @click="saveProduct">保存商品</el-button></template></el-dialog><el-dialog v-model="skuDialog" :title="editingSkuId ? '编辑 SKU' : '新增 SKU'" width="520px" append-to-body><el-form :model="skuForm" label-width="90px"><el-form-item label="SKU 编码" required><el-input v-model="skuForm.skuCode" placeholder="例如 DD-PHONE-BLUE" /></el-form-item><el-form-item label="规格 JSON" required><el-input v-model="skuForm.specJson" type="textarea" :rows="3" placeholder='{"颜色":"蓝色"}' /></el-form-item><el-form-item label="价格" required><el-input-number v-model="skuForm.price" :min="0.01" :precision="2" :step="1" /></el-form-item><el-form-item label="可用库存" required><el-input-number v-model="skuForm.availableStock" :min="0" :step="1" /></el-form-item><el-form-item label="状态"><el-radio-group v-model="skuForm.status"><el-radio-button :value="1">上架</el-radio-button><el-radio-button :value="0">下架</el-radio-button></el-radio-group></el-form-item></el-form><template #footer><el-button @click="skuDialog = false">取消</el-button><el-button type="primary" :loading="skuSaving" @click="saveSku">保存 SKU</el-button></template></el-dialog></div></template>
